import { useState, useEffect } from "react";

const CURRENT_YEAR = new Date().getFullYear();

// Load Montserrat font
const fontLink = document.createElement("link");
fontLink.href = "https://fonts.googleapis.com/css2?family=Montserrat:wght@700&display=swap";
fontLink.rel = "stylesheet";
document.head.appendChild(fontLink);

const systemPrompt = `You are a severe weather research assistant specializing in hail and storm data. When given an address, perform ONE focused web search for NOAA Storm Events Database records for that location's county/state covering the past 5 years, then immediately return the JSON. Do not perform multiple searches — gather everything needed in a single search query and synthesize the result.

Return ONLY valid JSON (no markdown, no backticks, no preamble) with this exact structure:
{
  "location": {
    "address": "...",
    "county": "...",
    "state": "...",
    "lat": "...",
    "lon": "..."
  },
  "summary": "2-3 sentence plain-English summary of hail risk for this area",
  "riskLevel": "Low" | "Moderate" | "High" | "Very High",
  "hailEvents": [
    {
      "date": "YYYY-MM-DD",
      "size": "X.XX inches (description)",
      "location": "city/area",
      "injuries": 0,
      "deaths": 0,
      "propertyDamage": "$X,XXX",
      "source": "NOAA Storm Events"
    }
  ],
  "otherEvents": [
    {
      "date": "YYYY-MM-DD",
      "type": "Tornado | Thunderstorm Wind | Flash Flood | etc",
      "description": "brief description",
      "damage": "$X,XXX or N/A"
    }
  ],
  "stats": {
    "totalHailEvents": 0,
    "largestHailSize": "X.XX inches",
    "avgEventsPerYear": "X.X",
    "mostActiveMonth": "Month",
    "yearsSearched": "YYYY-YYYY"
  },
  "sources": ["url1", "url2"]
}`;

export default function HailLookup() {
  const [address, setAddress] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [rawLog, setRawLog] = useState(null);
  const [isMobile, setIsMobile] = useState(() => window.innerWidth < 640);

  // iOS PWA install banner
  const isIos = () => /iphone|ipad|ipod/i.test(navigator.userAgent);
  const isInStandaloneMode = () => window.navigator.standalone === true;
  const [showIosBanner, setShowIosBanner] = useState(() => isIos() && !isInStandaloneMode());

  useEffect(() => {
    const onResize = () => setIsMobile(window.innerWidth < 640);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  const getRiskColor = (level) => {
    const map = {
      "Low": { bg: "#1a3a1a", text: "#4ade80", border: "#166534" },
      "Moderate": { bg: "#3a2e00", text: "#fbbf24", border: "#92400e" },
      "High": { bg: "#3a1a00", text: "#fb923c", border: "#9a3412" },
      "Very High": { bg: "#3a0000", text: "#f87171", border: "#991b1b" },
    };
    return map[level] || map["Low"];
  };

  const callAPI = async (messages) => {
    const response = await fetch("/api/anthropic", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        model: "claude-sonnet-4-6",
        max_tokens: 4000,
        system: systemPrompt,
        tools: [{ type: "web_search_20250305", name: "web_search" }],
        messages,
      }),
    });
    const text = await response.text();
    let data;
    try {
      data = JSON.parse(text);
    } catch {
      throw new Error(`Server error: ${text.slice(0, 150)}`);
    }
    if (!response.ok) {
      throw new Error(data.error?.message || `HTTP ${response.status}`);
    }
    return data;
  };

  const lookup = async () => {
    if (!address.trim()) return;
    setLoading(true);
    setResult(null);
    setError(null);
    setRawLog(null);

    try {
      let messages = [
        {
          role: "user",
          content: `Look up hail and severe weather data for this address: ${address}\n\nSearch for NOAA storm events for the past 5 years (${CURRENT_YEAR - 5} to ${CURRENT_YEAR}). Return only valid JSON as specified.`,
        },
      ];

      let data;
      // Max 2 rounds: 1 search + 1 synthesis (keeps within Vercel free tier 60s limit)
      for (let round = 0; round < 2; round++) {
        data = await callAPI(messages);

        if (data.stop_reason === "end_turn") break;

        // If the model used tools, feed results back and continue
        if (data.stop_reason === "tool_use") {
          // Append the assistant's response (with tool_use blocks)
          messages = [...messages, { role: "assistant", content: data.content }];

          // Build tool_result blocks for every tool_use block
          const toolResults = data.content
            .filter((b) => b.type === "tool_use")
            .map((b) => ({
              type: "tool_result",
              tool_use_id: b.id,
              content: b.content ?? "Search completed.",
            }));

          messages = [...messages, { role: "user", content: toolResults }];
        } else {
          // Any other stop reason — just break
          break;
        }
      }

      setRawLog(data);

      // Extract the final text block(s) and parse JSON
      const textBlocks = (data?.content || []).filter((b) => b.type === "text");
      const rawText = textBlocks.map((b) => b.text).join("\n");
      const cleaned = rawText.replace(/```json|```/g, "").trim();

      // Find the JSON object in the response (handles any leading prose)
      const jsonStart = cleaned.indexOf("{");
      const jsonEnd = cleaned.lastIndexOf("}");
      if (jsonStart === -1 || jsonEnd === -1) throw new Error("No JSON found in response.");
      const parsed = JSON.parse(cleaned.slice(jsonStart, jsonEnd + 1));
      setResult(parsed);
    } catch (err) {
      setError("Failed to retrieve weather data. " + err.message);
    } finally {
      setLoading(false);
    }
  };

  const riskColors = result ? getRiskColor(result.riskLevel) : null;

  return (
    <div style={{
      minHeight: "100vh",
      background: "#0a0c10",
      color: "#e2e8f0",
      fontFamily: "'Courier New', monospace",
      padding: "0"
    }}>
      {/* Header */}
      <div style={{
        background: "linear-gradient(180deg, #0d1117 0%, #0a0c10 100%)",
        borderBottom: "1px solid #1e3a5f",
        padding: isMobile ? "12px 16px" : "16px 32px",
        display: "flex",
        alignItems: "center",
        gap: isMobile ? "12px" : "24px",
        flexWrap: "wrap"
      }}>
        {/* Trinity Logo */}
        <img
          src="data:image/png;base64,"
          alt="Trinity Engineering"
          style={{ height: isMobile ? 48 : 72, width: "auto", display: "block", mixBlendMode: "lighten" }}
        />
        {/* Title + subtitle with storm icon centered */}
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <div style={{ fontSize: isMobile ? 15 : 22, fontWeight: 700, color: "#ffffff", letterSpacing: "0.05em", textTransform: "uppercase", fontFamily: "'Montserrat', sans-serif" }}>
            SEVERE WEATHER INTELLIGENCE
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ fontSize: 18 }}>🌩</span>
            <span style={{ fontSize: 11, color: "#4a6a8a", letterSpacing: "0.2em" }}>
              NOAA STORM EVENTS DATABASE · 5-YEAR LOOKBACK
            </span>
          </div>
        </div>
        <div style={{ marginLeft: "auto", fontSize: 11, color: "#2a4a6a", textAlign: "right", display: isMobile ? "none" : "block" }}>
          <div>DATA SOURCE: NOAA NWS</div>
          <div>NCEI STORM EVENTS DB</div>
        </div>
      </div>

      {/* Search Area */}
      <div style={{ padding: isMobile ? "16px" : "32px", maxWidth: 900, margin: "0 auto" }}>
        <div style={{
          background: "#0d1117",
          border: "1px solid #1e3a5f",
          borderRadius: 8,
          padding: "24px",
          marginBottom: 24
        }}>
          <div style={{ fontSize: 11, color: "#4a6a8a", letterSpacing: "0.2em", marginBottom: 12 }}>
            PROPERTY ADDRESS LOOKUP
          </div>
          <div style={{ display: "flex", gap: 12, flexDirection: isMobile ? "column" : "row" }}>
            <input
              value={address}
              onChange={e => setAddress(e.target.value)}
              onKeyDown={e => e.key === "Enter" && lookup()}
              placeholder="123 Main St, Omaha, NE 68102"
              style={{
                flex: 1,
                background: "#070a0f",
                border: "1px solid #1e3a5f",
                color: "#93c5fd",
                padding: "12px 16px",
                fontSize: 14,
                fontFamily: "'Courier New', monospace",
                borderRadius: 4,
                outline: "none"
              }}
            />
            <button
              onClick={lookup}
              disabled={loading || !address.trim()}
              style={{
                background: loading ? "#0a2a4a" : "linear-gradient(135deg, #1e40af, #1e90ff)",
                color: "#fff",
                border: "none",
                padding: "12px 28px",
                borderRadius: 4,
                cursor: loading ? "wait" : "pointer",
                fontSize: 13,
                fontFamily: "'Courier New', monospace",
                letterSpacing: "0.1em",
                fontWeight: 700,
                boxShadow: loading ? "none" : "0 0 16px #1e90ff44"
              }}
            >
              {loading ? "SCANNING..." : "RUN QUERY"}
            </button>
          </div>
        </div>

        {/* Loading */}
        {loading && (
          <div style={{
            border: "1px solid #1e3a5f",
            borderRadius: 8,
            padding: "40px",
            textAlign: "center",
            background: "#0d1117"
          }}>
            <div style={{ fontSize: 36, marginBottom: 12 }}>🌩</div>
            <div style={{ color: "#60a5fa", fontSize: 13, letterSpacing: "0.2em" }}>
              QUERYING NOAA STORM DATABASE...
            </div>
            <div style={{ color: "#2a4a6a", fontSize: 11, marginTop: 8, letterSpacing: "0.15em" }}>
              SEARCHING 5 YEARS OF SEVERE WEATHER RECORDS
            </div>
          </div>
        )}

        {/* Error */}
        {error && (
          <div style={{
            border: "1px solid #7f1d1d",
            borderRadius: 8,
            padding: "20px",
            background: "#1a0000",
            color: "#f87171",
            fontSize: 13
          }}>
            ⚠ {error}
          </div>
        )}

        {/* Results */}
        {result && (
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>

            {/* Location + Risk */}
            <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 16 }}>
              <div style={{ border: "1px solid #1e3a5f", borderRadius: 8, padding: "20px", background: "#0d1117" }}>
                <div style={{ fontSize: 10, color: "#4a6a8a", letterSpacing: "0.2em", marginBottom: 10 }}>LOCATION IDENTIFIED</div>
                <div style={{ color: "#93c5fd", fontSize: 16, fontWeight: 700 }}>{result.location?.county}, {result.location?.state}</div>
                <div style={{ color: "#4a6a8a", fontSize: 12, marginTop: 4 }}>{result.location?.address}</div>
              </div>

              <div style={{
                border: `1px solid ${riskColors.border}`,
                borderRadius: 8,
                padding: "20px",
                background: riskColors.bg
              }}>
                <div style={{ fontSize: 10, color: "#4a6a8a", letterSpacing: "0.2em", marginBottom: 10 }}>HAIL RISK ASSESSMENT</div>
                <div style={{ color: riskColors.text, fontSize: 22, fontWeight: 700 }}>{result.riskLevel}</div>
                <div style={{ color: "#4a7a6a", fontSize: 11, marginTop: 4 }}>
                  {result.stats?.yearsSearched} · {result.stats?.totalHailEvents} events found
                </div>
              </div>
            </div>

            {/* Summary */}
            <div style={{ border: "1px solid #1e3a5f", borderRadius: 8, padding: "20px", background: "#0d1117" }}>
              <div style={{ fontSize: 10, color: "#4a6a8a", letterSpacing: "0.2em", marginBottom: 10 }}>WEATHER SUMMARY</div>
              <div style={{ color: "#cbd5e1", fontSize: 14, lineHeight: 1.7 }}>{result.summary}</div>
            </div>

            {/* Stats Bar */}
            {result.stats && (
              <div style={{
                display: "grid",
                gridTemplateColumns: "repeat(4, 1fr)",
                gap: 12
              }}>
                {[
                  { label: "TOTAL HAIL EVENTS", value: result.stats.totalHailEvents },
                  { label: "LARGEST HAIL", value: result.stats.largestHailSize },
                  { label: "AVG / YEAR", value: result.stats.avgEventsPerYear },
                  { label: "MOST ACTIVE MONTH", value: result.stats.mostActiveMonth }
                ].map(s => (
                  <div key={s.label} style={{
                    border: "1px solid #1e3a5f",
                    borderRadius: 8,
                    padding: "16px",
                    background: "#0d1117",
                    textAlign: "center"
                  }}>
                    <div style={{ fontSize: 9, color: "#4a6a8a", letterSpacing: "0.15em", marginBottom: 8 }}>{s.label}</div>
                    <div style={{ color: "#60a5fa", fontSize: 18, fontWeight: 700 }}>{s.value ?? "—"}</div>
                  </div>
                ))}
              </div>
            )}

            {/* Hail Events Table */}
            {result.hailEvents?.length > 0 && (
              <div style={{ border: "1px solid #1e3a5f", borderRadius: 8, background: "#0d1117", overflow: "hidden" }}>
                <div style={{ padding: "16px 20px", borderBottom: "1px solid #1e3a5f", fontSize: 10, color: "#4a6a8a", letterSpacing: "0.2em" }}>
                  HAIL EVENTS — PAST 5 YEARS
                </div>
                <div style={{ overflowX: "auto" }}>
                  <table style={{ width: "100%", borderCollapse: "collapse", fontSize: isMobile ? 11 : 12, minWidth: isMobile ? 480 : "auto" }}>
                    <thead>
                      <tr style={{ background: "#070a0f" }}>
                        {["DATE", "SIZE", "LOCATION", "PROPERTY DMG", "INJURIES", "DEATHS"].map(h => (
                          <th key={h} style={{ padding: isMobile ? "8px 10px" : "10px 16px", textAlign: "left", color: "#2a5a8a", fontSize: 9, letterSpacing: "0.15em", borderBottom: "1px solid #1a2a3a" }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {result.hailEvents.map((ev, i) => (
                        <tr key={i} style={{ borderBottom: "1px solid #0f1a24" }}>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: "#93c5fd" }}>{ev.date}</td>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: "#fbbf24", fontWeight: 700 }}>{ev.size}</td>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: "#cbd5e1" }}>{ev.location}</td>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: ev.propertyDamage !== "$0" ? "#f87171" : "#4a6a8a" }}>{ev.propertyDamage}</td>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: ev.injuries > 0 ? "#fb923c" : "#4a6a8a" }}>{ev.injuries}</td>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: ev.deaths > 0 ? "#f87171" : "#4a6a8a" }}>{ev.deaths}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {/* Other Events */}
            {result.otherEvents?.length > 0 && (
              <div style={{ border: "1px solid #1e3a5f", borderRadius: 8, background: "#0d1117", overflow: "hidden" }}>
                <div style={{ padding: "16px 20px", borderBottom: "1px solid #1e3a5f", fontSize: 10, color: "#4a6a8a", letterSpacing: "0.2em" }}>
                  OTHER SEVERE WEATHER EVENTS
                </div>
                <div style={{ overflowX: "auto" }}>
                  <table style={{ width: "100%", borderCollapse: "collapse", fontSize: isMobile ? 11 : 12, minWidth: isMobile ? 480 : "auto" }}>
                    <thead>
                      <tr style={{ background: "#070a0f" }}>
                        {["DATE", "TYPE", "DESCRIPTION", "DAMAGE"].map(h => (
                          <th key={h} style={{ padding: isMobile ? "8px 10px" : "10px 16px", textAlign: "left", color: "#2a5a8a", fontSize: 9, letterSpacing: "0.15em", borderBottom: "1px solid #1a2a3a" }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {result.otherEvents.map((ev, i) => (
                        <tr key={i} style={{ borderBottom: "1px solid #0f1a24" }}>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: "#93c5fd" }}>{ev.date}</td>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: "#a78bfa", fontWeight: 700 }}>{ev.type}</td>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: "#cbd5e1" }}>{ev.description}</td>
                          <td style={{ padding: isMobile ? "8px 10px" : "10px 16px", color: "#fb923c" }}>{ev.damage}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {/* Sources */}
            {result.sources?.length > 0 && (
              <div style={{ border: "1px solid #1a2a3a", borderRadius: 8, padding: "16px 20px", background: "#070a0f" }}>
                <div style={{ fontSize: 9, color: "#2a4a6a", letterSpacing: "0.2em", marginBottom: 10 }}>DATA SOURCES</div>
                <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                  {result.sources.map((s, i) => (
                    <a key={i} href={s} target="_blank" rel="noopener noreferrer" style={{ color: "#1e60af", fontSize: 11, textDecoration: "none" }}>
                      ↗ {s}
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* Empty state */}
        {!loading && !result && !error && (
          <div style={{
            border: "1px dashed #1e3a5f",
            borderRadius: 8,
            padding: "48px",
            textAlign: "center",
            color: "#2a4a6a"
          }}>
            <div style={{ fontSize: 48, marginBottom: 16, opacity: 0.4 }}>🌩</div>
            <div style={{ fontSize: 12, letterSpacing: "0.2em" }}>ENTER AN ADDRESS TO BEGIN STORM ANALYSIS</div>
            <div style={{ fontSize: 11, marginTop: 8, opacity: 0.6 }}>Searches NOAA storm events, hail records, and severe weather history</div>
          </div>
        )}
      </div>

      {/* iOS PWA Install Banner */}
      {showIosBanner && (
        <div style={{
          position: "fixed",
          bottom: 0,
          left: 0,
          right: 0,
          background: "#0d1117",
          borderTop: "1px solid #1e3a5f",
          padding: "16px 20px 28px",
          zIndex: 1000,
          boxShadow: "0 -4px 24px rgba(0,0,0,0.6)"
        }}>
          <div style={{ maxWidth: 500, margin: "0 auto", position: "relative" }}>
            <button
              onClick={() => setShowIosBanner(false)}
              style={{
                position: "absolute",
                top: 0,
                right: 0,
                background: "none",
                border: "none",
                color: "#4a6a8a",
                fontSize: 20,
                cursor: "pointer",
                lineHeight: 1,
                padding: "0 4px"
              }}
            >
              ×
            </button>
            <div style={{ fontSize: 10, color: "#4a6a8a", letterSpacing: "0.2em", marginBottom: 10 }}>
              INSTALL THIS APP
            </div>
            <div style={{ color: "#93c5fd", fontSize: 13, marginBottom: 12, lineHeight: 1.5 }}>
              Add to your home screen for quick access:
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {[
                { step: "1", text: 'Tap the Share button', icon: "⎋", note: "(the box with an arrow at the bottom of Safari)" },
                { step: "2", text: 'Scroll down and tap "Add to Home Screen"', icon: "＋", note: "" },
                { step: "3", text: 'Tap "Add" to confirm', icon: "✓", note: "" },
              ].map(({ step, text, note }) => (
                <div key={step} style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
                  <div style={{
                    minWidth: 22,
                    height: 22,
                    background: "#1e3a5f",
                    borderRadius: "50%",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    fontSize: 11,
                    color: "#60a5fa",
                    fontWeight: 700,
                    marginTop: 1
                  }}>
                    {step}
                  </div>
                  <div>
                    <span style={{ color: "#cbd5e1", fontSize: 13 }}>{text}</span>
                    {note && <div style={{ color: "#4a6a8a", fontSize: 11, marginTop: 2 }}>{note}</div>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
